import java.io.File;
import java.util.Scanner;

public class SecurePathTraversal {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter file path: ");
        String userInput = scanner.nextLine();

        if (isValidInput(userInput)) {
            String directoryPath = "/path/to/some/directory/";
            File file = new File(directoryPath + userInput);

            if (file.exists() && file.getAbsolutePath().startsWith(directoryPath)) {
                System.out.println("File found: " + file.getAbsolutePath());
            } else {
                System.out.println("File not found");
            }
        } else {
            System.out.println("Invalid input");
        }
    }

    private static boolean isValidInput(String userInput) {
        // Implement your validation logic here
        // Example: Allow only alphanumeric characters and specific symbols
        return userInput.matches("[a-zA-Z0-9_-]+");
    }
}

